'use client';

import { useSiteSettings } from '@/hooks/useSiteSettings';
import { LanguageSwitch } from './LanguageSwitch';

export function ConditionalLanguageSwitch() {
  const { settings, isLoading } = useSiteSettings();

  if (isLoading) {
    return <div className="w-8 h-8 animate-pulse bg-gray-200 dark:bg-gray-700 rounded" />;
  }

  if (!settings.languages.showInHeader) {
    return null;
  }

  return <LanguageSwitch />;
}